import pickle
import json
import os
from typing import Any, Dict, List, Union
from pathlib import Path
import hashlib


class UserPreferences:
    """Container for user preferences with validation"""
    
    ALLOWED_TYPES = (dict, list, str, int, float, bool, type(None))
    
    def __init__(self, data: Dict[str, Any]):
        self.data = self._validate_and_sanitize(data)
    
    def _validate_and_sanitize(self, obj: Any, depth: int = 0, max_depth: int = 50) -> Any:
        """Recursively validate and sanitize preference data"""
        if depth > max_depth:
            raise ValueError(f"Maximum nesting depth ({max_depth}) exceeded")
        
        if obj is None or isinstance(obj, (str, int, float, bool)):
            return obj
        
        if isinstance(obj, dict):
            return {
                str(k): self._validate_and_sanitize(v, depth + 1, max_depth)
                for k, v in obj.items()
            }
        
        if isinstance(obj, (list, tuple)):
            return [self._validate_and_sanitize(item, depth + 1, max_depth) for item in obj]
        
        if hasattr(obj, '__dict__'):
            return self._validate_and_sanitize(obj.__dict__, depth + 1, max_depth)
        
        raise TypeError(f"Unsupported type in preferences: {type(obj)}")
    
    def get(self, key: str, default: Any = None) -> Any:
        """Get preference value by key"""
        return self.data.get(key, default)
    
    def set(self, key: str, value: Any) -> None:
        """Set preference value"""
        self.data[key] = self._validate_and_sanitize(value)
    
    def to_dict(self) -> Dict[str, Any]:
        """Convert to dictionary"""
        return self.data.copy()


def _compute_checksum(data: bytes) -> str:
    """Compute SHA256 checksum of data"""
    return hashlib.sha256(data).hexdigest()


def save_preferences_json(preferences: Union[UserPreferences, Dict[str, Any]], filepath: str) -> None:
    """Save preferences to JSON file with checksum validation"""
    if isinstance(preferences, UserPreferences):
        data = preferences.to_dict()
    else:
        pref_obj = UserPreferences(preferences)
        data = pref_obj.to_dict()
    
    filepath = Path(filepath)
    filepath.parent.mkdir(parents=True, exist_ok=True)
    
    json_data = json.dumps(data, indent=2, sort_keys=True)
    json_bytes = json_data.encode('utf-8')
    checksum = _compute_checksum(json_bytes)
    
    temp_filepath = filepath.with_suffix('.tmp')
    
    with open(temp_filepath, 'w', encoding='utf-8') as f:
        f.write(json_data)
    
    checksum_filepath = filepath.with_suffix('.json.checksum')
    with open(checksum_filepath, 'w', encoding='utf-8') as f:
        f.write(checksum)
    
    temp_filepath.replace(filepath)


def load_preferences_json(filepath: str, validate_checksum: bool = True) -> UserPreferences:
    """Load preferences from JSON file with validation"""
    filepath = Path(filepath)
    
    if not filepath.exists():
        raise FileNotFoundError(f"Preferences file not found: {filepath}")
    
    with open(filepath, 'r', encoding='utf-8') as f:
        json_data = f.read()
    
    if validate_checksum:
        checksum_filepath = filepath.with_suffix('.json.checksum')
        if checksum_filepath.exists():
            with open(checksum_filepath, 'r', encoding='utf-8') as f:
                expected_checksum = f.read().strip()
            
            actual_checksum = _compute_checksum(json_data.encode('utf-8'))
            
            if actual_checksum != expected_checksum:
                raise ValueError("Checksum validation failed - file may be corrupted")
    
    try:
        data = json.loads(json_data)
    except json.JSONDecodeError as e:
        raise ValueError(f"Invalid JSON format: {e}")
    
    if not isinstance(data, dict):
        raise TypeError("Preferences root must be a dictionary")
    
    return UserPreferences(data)


def save_preferences_pickle(preferences: Union[UserPreferences, Dict[str, Any]], filepath: str) -> None:
    """Save preferences to pickle file (less safe, but supports more types)"""
    if isinstance(preferences, UserPreferences):
        data = preferences.to_dict()
    else:
        pref_obj = UserPreferences(preferences)
        data = pref_obj.to_dict()
    
    filepath = Path(filepath)
    filepath.parent.mkdir(parents=True, exist_ok=True)
    
    temp_filepath = filepath.with_suffix('.tmp')
    
    with open(temp_filepath, 'wb') as f:
        pickle.dump(data, f, protocol=pickle.HIGHEST_PROTOCOL)
    
    temp_filepath.replace(filepath)


def load_preferences_pickle(filepath: str) -> UserPreferences:
    """Load preferences from pickle file with validation"""
    filepath = Path(filepath)
    
    if not filepath.exists():
        raise FileNotFoundError(f"Preferences file not found: {filepath}")
    
    with open(filepath, 'rb') as f:
        data = pickle.load(f)
    
    if not isinstance(data, dict):
        raise TypeError("Preferences root must be a dictionary")
    
    return UserPreferences(data)


def save_preferences(preferences: Union[UserPreferences, Dict[str, Any]], 
                    filepath: str, 
                    format: str = 'json') -> None:
    """
    Save user preferences to file
    
    Args:
        preferences: UserPreferences object or dictionary
        filepath: Path to save file
        format: 'json' (safer, recommended) or 'pickle' (faster but less safe)
    """
    if format == 'json':
        save_preferences_json(preferences, filepath)
    elif format == 'pickle':
        save_preferences_pickle(preferences, filepath)
    else:
        raise ValueError(f"Unsupported format: {format}. Use 'json' or 'pickle'")


def load_preferences(filepath: str, 
                    format: str = 'json',
                    validate_checksum: bool = True) -> UserPreferences:
    """
    Load user preferences from file
    
    Args:
        filepath: Path to preferences file
        format: 'json' or 'pickle'
        validate_checksum: Whether to validate checksum (JSON only)
    
    Returns:
        UserPreferences object with validated data
    """
    if format == 'json':
        return load_preferences_json(filepath, validate_checksum)
    elif format == 'pickle':
        return load_preferences_pickle(filepath)
    else:
        raise ValueError(f"Unsupported format: {format}. Use 'json' or 'pickle'")


